// 7-Segment Display + Potentiometer Counter (0-9)
// Segments: a=D2, b=D3, c=D4, d=D5, e=D6, f=D7, g=D8
// Potentiometer: A0

const int segA = 2, segB = 3, segC = 4, segD = 5;
const int segE = 6, segF = 7, segG = 8;
const int potPin = A0;

void displayDigit(int digit) {
  int a, b, c, d, e, f, g;

  // Define segments for each digit (1 = ON, 0 = OFF)
  if (digit == 0) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0;
  } else if (digit == 1) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 2) {
    a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1;
  } else if (digit == 3) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1;
  } else if (digit == 4) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1;
  } else if (digit == 5) {
    a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else if (digit == 6) {
    a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 7) {
    a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 8) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 9) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1;
  }

  // Write segments
  digitalWrite(segA, a);
  digitalWrite(segB, b);
  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

void setup() {
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);
  pinMode(potPin, INPUT);
}

void loop() {
  int potValue = analogRead(potPin);
  int digit = map(potValue, 0, 1023, 0, 9);
  displayDigit(digit);
  delay(50);
}

