// 7-Segment Display + Potentiometer Counter (0-9)
// POT connected to A0, maps 0-1023 to display digit 0-9
// Segments: a=D2, b=D3, c=D4, d=D5, e=D6, f=D7, g=D8

const int segA = 2, segB = 3, segC = 4, segD = 5, segE = 6, segF = 7, segG = 8;
const int potPin = 14; // A0

int lastDigit = 0;
unsigned long lastReadTime = 0;
const unsigned long readDelay = 100; // Read every 100ms to avoid noise

void setup() {
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);
  pinMode(potPin, INPUT);
}

void displayDigit(int digit) {
  // Segment patterns for 0-9
  boolean a, b, c, d, e, f, g;

  if (digit == 0) { a=1; b=1; c=1; d=1; e=1; f=1; g=0; }
  else if (digit == 1) { a=0; b=1; c=1; d=0; e=0; f=0; g=0; }
  else if (digit == 2) { a=1; b=1; c=0; d=1; e=1; f=0; g=1; }
  else if (digit == 3) { a=1; b=1; c=1; d=1; e=0; f=0; g=1; }
  else if (digit == 4) { a=0; b=1; c=1; d=0; e=0; f=1; g=1; }
  else if (digit == 5) { a=1; b=0; c=1; d=1; e=0; f=1; g=1; }
  else if (digit == 6) { a=1; b=0; c=1; d=1; e=1; f=1; g=1; }
  else if (digit == 7) { a=1; b=1; c=1; d=0; e=0; f=0; g=0; }
  else if (digit == 8) { a=1; b=1; c=1; d=1; e=1; f=1; g=1; }
  else if (digit == 9) { a=1; b=1; c=1; d=1; e=0; f=1; g=1; }

  digitalWrite(segA, a);
  digitalWrite(segB, b);
  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

void loop() {
  unsigned long now = millis();
  if (now - lastReadTime >= readDelay) {
    lastReadTime = now;

    int rawValue = analogRead(potPin);
    int digit = rawValue / 102; // 1023 / 10 ≈ 102 per step
    if (digit > 9) digit = 9;

    if (digit != lastDigit) {
      lastDigit = digit;
      displayDigit(digit);
    }
  }
}

